--- README.md ---
# Lab Technician Landing Page

A minimal single-page landing site for a lab technician. It includes a hero section with title and subtitle, a services list, and a contact form that shows an alert (no backend).

Design uses only red, black, and white (and their shades) and is responsive from small to large screens.

## Getting Started

- Prerequisites: Node.js (LTS) and npm

### Install dependencies

```bash
npm install
```

### Run locally

This is a static site. Open `index.html` directly in your browser, or use any static file server.

Example (optional):

```bash
# using npx to serve locally (no install required)
npx http-server -c-1 -p 8080 .
# then open http://localhost:8080
```

### Run tests

```bash
npm test
```

The Jest test asserts that the hero title is present in the HTML.


--- __tests__/hero.test.js ---
const fs = require('fs');
const path = require('path');
const { JSDOM } = require('jsdom');

describe('Landing page hero', () => {
  test('has the hero title present', () => {
    const filePath = path.resolve(__dirname, '..', 'index.html');
    const html = fs.readFileSync(filePath, 'utf8');
    const dom = new JSDOM(html);
    const doc = dom.window.document;
    const title = doc.querySelector('#hero-title');
    expect(title).not.toBeNull();
    expect(title.textContent.trim()).toBe('Precise Lab Services');
  });
});


--- index.html ---
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Lab Technician</title>
  <link rel="stylesheet" href="styles.css" />
</head>
<body>
  <header class="hero">
    <div class="container">
      <h1 id="hero-title">Precise Lab Services</h1>
      <p class="subtitle">Reliable diagnostics and sample handling</p>
      <a href="#contact" class="btn btn-primary">Contact</a>
    </div>
  </header>

  <main>
    <section class="section services" id="services">
      <div class="container">
        <h2 class="section-title">Services</h2>
        <ul class="services-list" aria-label="List of services">
          <li class="service-card">
            <h3>Sample Collection</h3>
            <p>Safe and sterile collection for a variety of tests.</p>
          </li>
          <li class="service-card">
            <h3>Diagnostic Testing</h3>
            <p>Accurate processing with calibrated equipment.</p>
          </li>
          <li class="service-card">
            <h3>Quality Control</h3>
            <p>Routine checks to ensure reliable results.</p>
          </li>
        </ul>
      </div>
    </section>

    <section class="section contact" id="contact">
      <div class="container">
        <h2 class="section-title">Contact</h2>
        <form id="contact-form" class="contact-form" novalidate>
          <div class="form-row">
            <label for="name">Name</label>
            <input id="name" name="name" type="text" required placeholder="Your name" />
          </div>
          <div class="form-row">
            <label for="email">Email</label>
            <input id="email" name="email" type="email" required placeholder="you@example.com" />
          </div>
          <div class="form-row">
            <label for="message">Message</label>
            <textarea id="message" name="message" rows="4" required placeholder="How can we help?"></textarea>
          </div>
          <button type="submit" class="btn btn-accent">Send</button>
        </form>
      </div>
    </section>
  </main>

  <footer class="site-footer">
    <div class="container">
      <small>&copy; <span id="year"></span> Precise Lab Services</small>
    </div>
  </footer>

  <script src="script.js"></script>
</body>
</html>


